from flask import Flask, request, jsonify
from itsdangerous import URLSafeTimedSerializer, BadSignature, SignatureExpired

app = Flask(__name__)

# Configurable algorithms and keys
ALGORITHMS = {
    'HS256': 'secret_key_1',
    'RS256': 'public_key_path_2'
}

def verify_jwt(token, algorithm='HS256'):
    serializer = URLSafeTimedSerializer(ALGORITHMS.get(algorithm))
    try:
        payload = serializer.loads(token, max_age=3600)  # Token expires in 1 hour
        return payload
    except (BadSignature, SignatureExpired):
        return None

@app.route('/verify-token', methods=['POST'])
def verify_token():
    data = request.get_json()
    token = data.get('token')
    algorithm = data.get('algorithm', 'HS256')

    if not token:
        return jsonify({'error': 'Missing token'}), 400

    payload = verify_jwt(token, algorithm)
    
    if payload is None:
        return jsonify({'error': 'Invalid token'}), 401
    
    return jsonify({'payload': payload}), 200

if __name__ == '__main__':
    app.run(debug=True)